import React from 'react';
import { Link } from 'react-router-dom';

function MainMenu() {
  return (
    <div style={styles.container}>
      <h1 style={styles.title}>YallaShoot</h1>
      <nav style={styles.menu}>
        <Link to="/start-game" style={styles.button}>Start Game</Link>
        <Link to="/create-game" style={styles.button}>Create Game</Link>
        <Link to="/set-game" style={styles.button}>Set Game</Link>
        <Link to="/players" style={styles.button}>Players Setting</Link>
        <Link to="/history" style={styles.button}>History</Link>
      </nav>
    </div>
  );
}

const styles = {
  container: {
    textAlign: 'center',
    padding: '50px',
    fontFamily: 'Arial, sans-serif',
  },
  title: {
    fontSize: '48px',
    marginBottom: '40px',
  },
  menu: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px',
  },
  button: {
    padding: '15px 30px',
    fontSize: '18px',
    textDecoration: 'none',
    backgroundColor: '#4CAF50',
    color: 'white',
    borderRadius: '8px',
  }
};

export default MainMenu;
